// ============================================
// Navbar Component
// ============================================

import React, { useState } from 'react';
import { WiDaySunny } from 'react-icons/wi';
import { FiSun, FiMoon, FiLogOut, FiUser, FiMenu, FiX } from 'react-icons/fi';
import { useAuth } from '../context/AuthContext';
import { useWeather } from '../context/WeatherContext';

const Navbar = ({ onShowAuth }) => {
  const { user, isAuthenticated, logout } = useAuth();
  const { darkMode, toggleDarkMode } = useWeather();
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <nav className="relative z-50 px-4 py-4">
      <div className="max-w-7xl mx-auto flex items-center justify-between">

        {/* Logo */}
        <div className="flex items-center gap-2">
          <WiDaySunny className="text-yellow-300 text-4xl" />
          <div>
            <h1 className="text-white font-bold text-xl leading-tight">AI Weather</h1>
            <p className="text-blue-200 text-xs">Dashboard</p>
          </div>
        </div>

        {/* Desktop Nav */}
        <div className="hidden md:flex items-center gap-3">

          {/* Dark Mode Toggle */}
          <button
            onClick={toggleDarkMode}
            className="glass rounded-full p-2.5 text-white hover:bg-white/20 transition-all"
            title={darkMode ? 'Switch to Light Mode' : 'Switch to Dark Mode'}
          >
            {darkMode ? <FiSun className="text-yellow-300 text-lg" /> : <FiMoon className="text-lg" />}
          </button>

          {isAuthenticated ? (
            <div className="flex items-center gap-3">
              {/* User Info */}
              <div className="glass rounded-full px-4 py-2 flex items-center gap-2">
                <FiUser className="text-blue-200 text-sm" />
                <span className="text-white text-sm font-medium">{user?.name}</span>
              </div>
              {/* Logout Button */}
              <button
                onClick={logout}
                className="glass rounded-full px-4 py-2 flex items-center gap-2 text-white hover:bg-red-500/30 transition-all"
              >
                <FiLogOut className="text-sm" />
                <span className="text-sm">Logout</span>
              </button>
            </div>
          ) : (
            <button
              onClick={onShowAuth}
              className="bg-white/20 hover:bg-white/30 text-white rounded-full px-5 py-2 font-medium text-sm transition-all backdrop-blur-sm border border-white/20"
            >
              Login / Register
            </button>
          )}
        </div>

        {/* Mobile Menu Button */}
        <button
          className="md:hidden text-white p-2"
          onClick={() => setMenuOpen(!menuOpen)}
        >
          {menuOpen ? <FiX className="text-xl" /> : <FiMenu className="text-xl" />}
        </button>
      </div>

      {/* Mobile Menu */}
      {menuOpen && (
        <div className="md:hidden mt-3 glass rounded-2xl p-4 mx-4 animate-fade-in">
          <div className="flex flex-col gap-3">
            <button
              onClick={toggleDarkMode}
              className="flex items-center gap-3 text-white py-2"
            >
              {darkMode ? <FiSun className="text-yellow-300" /> : <FiMoon />}
              <span>{darkMode ? 'Light Mode' : 'Dark Mode'}</span>
            </button>

            {isAuthenticated ? (
              <>
                <div className="flex items-center gap-3 text-white py-2">
                  <FiUser />
                  <span>{user?.name}</span>
                </div>
                <button onClick={() => { logout(); setMenuOpen(false); }}
                  className="flex items-center gap-3 text-red-300 py-2">
                  <FiLogOut />
                  <span>Logout</span>
                </button>
              </>
            ) : (
              <button
                onClick={() => { onShowAuth(); setMenuOpen(false); }}
                className="text-white font-medium py-2 text-left"
              >
                Login / Register
              </button>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
